kml.Document:
LCPsych Office Locations

{% for office in offices %}

  {{ office.name }}

    <p><strong>{{ office.name }}</strong></p>
    {% if office.full_address %}<p>{{ office.full_address|linebreaksbr }}</p>{% endif %}
    {% if office.phone_number %}<p>{{ office.phone_label }}: {{ office.phone_number }}</p>{% endif %}
    {% if office.fax_number %}<p>{{ office.fax_label }}: {{ office.fax_number }}</p>{% endif %}
    {% if office.office_hours %}<p>{{ office.office_hours_title }}:<br>{{ office.office_hours|linebreaksbr }}</p>{% endif %}
    {% if office.cta_url %}<p><a href="{{ office.cta_url }}">{{ office.cta_label }}</a></p>{% endif %}

  {% if office.latitude and office.longitude %}

    {{ office.longitude }},{{ office.latitude }},0

  {% endif %}
  {% if office.directions_url %}{% endif %}

    {% if office.address_line1 %}{{ office.address_line1 }}{% if office.address_line2 %}, {{ office.address_line2 }}{% endif %}{% endif %}
    {% if office.address_city %}{{ office.address_city }}{% endif %}
    {% if office.address_state %}{{ office.address_state }}{% endif %}
    {% if office.address_zip %}{{ office.address_zip }}{% endif %}
    US
    {% if office.phone_number %}{{ office.phone_number }}{% endif %}
    {% if office.office_hours %}{{ office.office_hours }}{% endif %}
    {% if office.cta_url %}{{ office.cta_url }}{% endif %}


{% endfor %}
